changeSet.sql:
ALTER TABLE technologies ADD COLUMN risk_reduction double precision DEFAULT 0;
UPDATE technologies SET risk_reduction = 0 WHERE risk_reduction IS NULL;

ALTER TABLE technologies ADD COLUMN risk_reduction_percent double precision DEFAULT 0;
UPDATE technologies SET risk_reduction_percent = 0 WHERE risk_reduction_percent IS NULL;

ALTER TABLE technologies ADD COLUMN tool_price double precision DEFAULT 0;
UPDATE technologies SET tool_price = 0 WHERE tool_price IS NULL;

rollback.sql:
ALTER TABLE technologies DROP COLUMN risk_reduction;
ALTER TABLE technologies DROP COLUMN risk_reduction_percent;
ALTER TABLE technologies DROP COLUMN tool_price;
